/* --------------------------- Helpers --------------------------- */

private fun countdownText(now: Double, target: Double): String {
    var diff = target - now
    if (diff < 0) diff += 24.0
    val hours = floor(diff).toInt()
    val mins = ((diff - hours) * 60.0).toInt().coerceAtLeast(0)
    return when {
        hours > 0 -> "${hours}h ${mins}m"
        else -> "${abs(mins)}m"
    }
}

